// AUTO-GENERATED per-check bilingual catalogue (#1/#53): purpose ("why") + localized
// fix for every check. Generated from each check source, sample-verified for accuracy.
// The dynamic per-check `message` stays English for now (see backlog #1).
import type { Lang } from './i18n.js';

export interface CheckI18n { why: Record<Lang, string>; fix?: Record<Lang, string>; }

export const CHECK_I18N: Record<string, CheckI18n> = {
  "about-contact": { why: { en: "Checks that reachable /about and /contact pages exist and that a contact method (tel, email, or ContactPoint) is exposed. These trust signals help users and AI engines confirm that a real, accountable organization stands behind the site.", fr: "Vérifie que des pages /about et /contact accessibles existent et qu’un moyen de contact (tel, email ou ContactPoint) est exposé. Ces signaux de confiance aident les utilisateurs et les moteurs d’IA à confirmer qu’une organisation réelle et responsable se trouve derrière le site." }, fix: { en: "Publish linked /about and /contact pages and expose a contact method (tel/email/ContactPoint).", fr: "Publiez des pages /about et /contact liées et exposez un moyen de contact (tel/email/ContactPoint)." } },
  "ai-crawlers-allowed": { why: { en: "Checks that robots.txt does not block AI crawlers, separating citation-time fetchers (a hard fail) from training-only bots (a softer warning). If a citation-time fetcher is disallowed, that assistant simply cannot read or cite your site in its live answers — the single highest-weighted check.", fr: "Vérifie que le robots.txt ne bloque pas les robots d'IA, en distinguant les robots de citation en temps réel (échec) des robots d'entraînement seul (simple avertissement). Si un robot de citation est interdit, l'assistant ne peut tout simplement pas lire ni citer votre site dans ses réponses en direct — c'est le contrôle au poids le plus élevé." }, fix: { en: "Never \"Disallow: /\" a citation-time fetcher (OAI-SearchBot, ChatGPT-User, Perplexity-User, Claude-User, PerplexityBot) — it hides the site from live AI answers.", fr: "Ne mettez jamais « Disallow: / » pour un robot de citation en temps réel (OAI-SearchBot, ChatGPT-User, Perplexity-User, Claude-User, PerplexityBot) — cela masque le site dans les réponses des IA en direct." } },
  "alt-descriptive": { why: { en: "Checks that non-empty `alt` attributes are real descriptions rather than filenames or placeholders like \"image\" or \"IMG_1234.jpg\". Meaningful alt text helps screen readers and lets image search and AI engines understand what each picture shows.", fr: "Vérifie que les attributs `alt` non vides sont de vraies descriptions plutôt que des noms de fichiers ou des mots passe-partout comme « image » ou « IMG_1234.jpg ». Un texte alternatif pertinent aide les lecteurs d'écran et permet à la recherche d'images et aux moteurs d'IA de comprendre ce que montre chaque visuel." }, fix: { en: "Replace filename/placeholder alt text (\"image\", \"IMG_1234.jpg\") with a real description of the image.", fr: "Remplacez les textes alternatifs qui reprennent un nom de fichier ou un mot passe-partout (« image », « IMG_1234.jpg ») par une vraie description de l'image." } },
  "anchor-text": { why: { en: "Measures the share of internal links that use generic text like \"click here\", \"read more\", or a bare URL. Descriptive anchor text tells search engines and AI what the linked page is about, helping both navigation and understanding.", fr: "Mesure la proportion de liens internes utilisant un texte générique comme « cliquez ici », « en savoir plus » ou une URL brute. Un texte de lien descriptif indique aux moteurs de recherche et à l’IA de quoi parle la page liée, ce qui facilite à la fois la navigation et la compréhension." }, fix: { en: "Name the destination in the anchor text instead of \"click here\" / \"read more\" / bare URLs.", fr: "Nommez la destination dans le texte du lien au lieu de « cliquez ici » / « en savoir plus » / d’URL brutes." } },
  "answer-headings": { why: { en: "On long pages (≥300 words), checks that at least one H2/H3 is phrased as a question (starts with what/how/why… or ends with \"?\"). Question-style headings mirror how people query AI assistants and make passages easy to lift as answers.", fr: "Sur les pages longues (≥300 mots), vérifie qu’au moins un H2/H3 est formulé comme une question (commence par quoi/comment/pourquoi… ou se termine par « ? »). Ces sous-titres reflètent la façon dont on interroge les assistants IA et facilitent la reprise de passages comme réponses." }, fix: { en: "Phrase subheads as the questions readers ask (start with what/how/why/… or end with \"?\").", fr: "Formulez les sous-titres comme les questions que se posent les lecteurs (commencez par quoi/comment/pourquoi/… ou terminez par « ? »)." } },
  "asset-caching": { why: { en: "Samples a same-origin CSS/JS asset and checks for a Cache-Control max-age or ETag. Cache headers let browsers reuse assets on repeat visits instead of re-downloading them.", fr: "Échantillonne un fichier CSS/JS du même domaine et vérifie la présence d'un Cache-Control max-age ou d'un ETag. Ces en-têtes de cache permettent aux navigateurs de réutiliser les fichiers lors des visites suivantes au lieu de les retélécharger." }, fix: { en: "Cache-Control: public, max-age=31536000, immutable on hashed assets.", fr: "Servez les fichiers versionnés (hashés) avec l'en-tête Cache-Control: public, max-age=31536000, immutable." } },
  "broken-internal-links": { why: { en: "Follows every internal link found on the sampled pages and flags any that return an error status (>= 400) or fail to load. Dead links waste crawler budget and stop search and AI engines from reaching parts of your site.", fr: "Suit chaque lien interne trouvé sur les pages échantillonnées et signale ceux qui renvoient un code d’erreur (≥ 400) ou ne se chargent pas. Les liens morts gaspillent le budget de crawl et empêchent les moteurs de recherche et d’IA d’atteindre certaines parties de votre site." }, fix: { en: "Fix or remove links returning >= 400 so crawlers do not waste budget on dead ends.", fr: "Corrigez ou supprimez les liens renvoyant un code ≥ 400 afin que les crawlers ne gaspillent pas leur budget dans des impasses." } },
  "canonical": { why: { en: "Verifies each sampled page declares a single, absolute canonical URL pointing to itself on the same origin, rather than a blanket canonical to the homepage. This tells search engines and AI crawlers which URL is authoritative and prevents duplicate-content dilution.", fr: "Vérifie que chaque page échantillonnée déclare une URL canonique unique, absolue et pointant vers elle-même sur la même origine, plutôt qu’une canonique globale vers l’accueil. Cela indique aux moteurs de recherche et aux robots d’IA quelle URL fait autorité et évite la dilution due au contenu dupliqué." }, fix: { en: "One absolute, self-referential canonical per page (tag or HTTP Link header).", fr: "Une seule balise canonique absolue et auto-référente par page (balise ou en-tête HTTP Link)." } },
  "canonical-resolves": { why: { en: "Fetches every declared <link rel=\"canonical\"> target and verifies it returns HTTP 200, is indexable (not noindex), and does not itself redirect. A canonical pointing at a broken, noindexed, or redirecting page confuses search engines and AI crawlers about which URL to index.", fr: "Récupère chaque cible <link rel=\"canonical\"> déclarée et vérifie qu'elle renvoie un code HTTP 200, qu'elle est indexable (pas en noindex) et qu'elle ne redirige pas elle-même. Une canonique qui pointe vers une page cassée, en noindex ou avec redirection perturbe les moteurs de recherche et les robots d'IA sur l'URL à indexer." }, fix: { en: "Point canonicals only at live (200), indexable, non-redirecting URLs.", fr: "Faites pointer les canoniques uniquement vers des URL vivantes (200), indexables et sans redirection." } },
  "charset": { why: { en: "Checks that the homepage declares a character encoding, ideally UTF-8. Without a declared charset, browsers and crawlers can misread accented or non-Latin characters and corrupt your content.", fr: "Vérifie que la page d’accueil déclare un encodage de caractères, idéalement UTF-8. Sans charset déclaré, les navigateurs et les robots peuvent mal interpréter les caractères accentués ou non latins et corrompre votre contenu." }, fix: { en: "Add <meta charset=\"utf-8\"> first in <head>.", fr: "Ajoutez <meta charset=\"utf-8\"> en premier dans le <head>." } },
  "clickjacking": { why: { en: "Verifies the page defends against being embedded in a hostile frame, via an X-Frame-Options header or a CSP frame-ancestors directive delivered over HTTP. Anti-clickjacking protection stops attackers from tricking users through an invisible overlay of your site and is a standard security signal of a trustworthy page.", fr: "Vérifie que la page se protège contre son intégration dans un cadre hostile, via un en-tête X-Frame-Options ou une directive CSP frame-ancestors transmise en HTTP. La protection anti-clickjacking empêche les attaquants d’abuser les utilisateurs au moyen d’une surcouche invisible de votre site et constitue un signal de sécurité standard d’une page digne de confiance." }, fix: { en: "Add `X-Frame-Options: SAMEORIGIN` or a CSP `frame-ancestors 'self'`.", fr: "Ajoutez `X-Frame-Options: SAMEORIGIN` ou une directive CSP `frame-ancestors 'self'`." } },
  "content-author-eeat": { why: { en: "On article pages, checks for a named Person author in JSON-LD plus a visible byline. Clear authorship is a core E-E-A-T signal that search and AI engines use to judge whether content is trustworthy.", fr: "Sur les pages d’article, recherche un auteur de type Person nommé dans le JSON-LD ainsi qu’une signature visible. Une paternité claire est un signal E-E-A-T essentiel que les moteurs de recherche et d’IA utilisent pour juger de la fiabilité du contenu." }, fix: { en: "Add a visible byline linking a bio plus JSON-LD author {@type:Person, name, url, jobTitle}.", fr: "Ajoutez une signature visible renvoyant vers une bio, plus un auteur JSON-LD {@type:Person, name, url, jobTitle}." } },
  "content-depth": { why: { en: "Checks that each page's main content meets a word-count threshold (≥300 words for articles, ≥150 for other pages). Thin pages give search and AI engines little substance to extract or cite.", fr: "Vérifie que le contenu principal de chaque page atteint un seuil de mots (≥300 mots pour les articles, ≥150 pour les autres pages). Les pages trop minces offrent peu de matière à extraire ou à citer pour les moteurs de recherche et d’IA." }, fix: { en: "Expand or consolidate thin pages with substantive copy (≥300 words for articles, ≥150 for other pages).", fr: "Étoffez ou regroupez les pages trop minces avec du contenu substantiel (≥300 mots pour les articles, ≥150 pour les autres pages)." } },
  "content-freshness": { why: { en: "On article pages, checks for machine-readable, recent publish/modified dates (ISO-8601 in JSON-LD, meta tags, or <time>) no older than about 24 months. Fresh, clearly dated content signals reliability to search and AI answer engines.", fr: "Sur les pages d’article, recherche des dates de publication/modification lisibles par machine et récentes (ISO-8601 dans le JSON-LD, les balises meta ou <time>), datant de moins de 24 mois environ. Un contenu récent et clairement daté signale la fiabilité aux moteurs de recherche et de réponse IA." }, fix: { en: "Emit ISO-8601 datePublished + dateModified (and a visible date) on article pages; keep them real and recent.", fr: "Émettez des dates datePublished + dateModified au format ISO-8601 (et une date visible) sur les pages d’article ; gardez-les réelles et récentes." } },
  "content-lead-answer": { why: { en: "Checks that each page opens with a concise direct answer or definition (≈40–320 characters), or a TL;DR block, right after the H1. Answer engines favor content that states the key point up front rather than burying it.", fr: "Vérifie que chaque page commence par une réponse ou définition directe et concise (≈40–320 caractères), ou un bloc TL;DR, juste après le H1. Les moteurs de réponse privilégient le contenu qui énonce l’essentiel d’emblée plutôt que de l’enfouir." }, fix: { en: "Open each page with a 1–2 sentence direct answer/definition (≈40–320 chars) or a TL;DR block right after the H1.", fr: "Commencez chaque page par une réponse ou définition directe de 1 à 2 phrases (≈40–320 caractères) ou un bloc TL;DR juste après le H1." } },
  "content-readability": { why: { en: "Estimates the reading grade level of the homepage main text using a Flesch-Kincaid formula. Simpler, shorter sentences are easier for readers and for AI models to summarize and quote accurately.", fr: "Estime le niveau de lecture du texte principal de la page d’accueil à l’aide d’une formule de Flesch-Kincaid. Des phrases plus courtes et plus simples sont plus faciles à lire et permettent aux modèles d’IA de résumer et de citer votre contenu avec justesse." }, fix: { en: "Break long sentences and paragraphs into shorter, simpler ones.", fr: "Découpez les phrases et paragraphes longs en énoncés plus courts et plus simples." } },
  "content-uniqueness": { why: { en: "Compares the main text of sampled pages using shingle/Jaccard similarity to flag near-duplicate bodies (≥0.8 overlap). Duplicate content dilutes ranking and confuses AI engines about which URL to trust and cite.", fr: "Compare le texte principal des pages échantillonnées via une similarité de shingles/Jaccard pour repérer les corps quasi identiques (recouvrement ≥0,8). Le contenu dupliqué dilue le classement et empêche les moteurs d’IA de savoir quelle URL privilégier et citer." }, fix: { en: "Give each URL unique content, or canonicalize duplicates to one URL.", fr: "Donnez à chaque URL un contenu unique, ou canonicalisez les doublons vers une seule URL." } },
  "content-without-js": { why: { en: "Verifies each sampled page exposes at least 200 characters of visible text without running JavaScript. AI crawlers generally don't execute JS, so content that only appears after client-side rendering is invisible to them.", fr: "Vérifie que chaque page échantillonnée expose au moins 200 caractères de texte visible sans exécuter JavaScript. Les crawlers IA n’exécutent généralement pas le JS : un contenu qui n’apparaît qu’après un rendu côté client leur reste invisible." }, fix: { en: "Server-render (SSR/SSG) your main content: AI crawlers do not execute JavaScript.", fr: "Rendez votre contenu principal côté serveur (SSR/SSG) : les crawlers IA n’exécutent pas JavaScript." } },
  "crawlable-nav": { why: { en: "Counts navigation links and flags pages where too many require JavaScript to work (href=\"#\", javascript:, or no href). AI answer-engine crawlers (GPTBot, ClaudeBot, PerplexityBot) and Google's first pass do not run JavaScript, so JS-only navigation hides those pages from them.", fr: "Compte les liens de navigation et signale les pages où trop d'entre eux nécessitent JavaScript pour fonctionner (href=\"#\", javascript: ou pas de href). Les robots des moteurs de réponse IA (GPTBot, ClaudeBot, PerplexityBot) et le premier passage de Google n'exécutent pas JavaScript, si bien qu'une navigation uniquement en JS leur cache ces pages." }, fix: { en: "Use real <a href=\"/path\"> links for navigation so crawlers that do not run JavaScript (AI answer-engine bots, and Google's first pass) can reach every page.", fr: "Utilisez de vrais liens <a href=\"/path\"> pour la navigation afin que les robots qui n'exécutent pas JavaScript (robots des moteurs de réponse IA et premier passage de Google) puissent atteindre chaque page." } },
  "csp": { why: { en: "Checks for a Content-Security-Policy that restricts which scripts, styles and connections the page may load, and warns when it still allows 'unsafe-inline' or wildcard sources. A strong CSP limits cross-site scripting and signals a well-secured, trustworthy site to search and AI engines.", fr: "Vérifie la présence d’une Content-Security-Policy qui restreint les scripts, styles et connexions que la page peut charger, et alerte lorsqu’elle autorise encore « 'unsafe-inline' » ou des sources joker. Une CSP solide limite les attaques par injection de scripts (XSS) et signale aux moteurs de recherche et d’IA un site bien sécurisé et digne de confiance." }, fix: { en: "Add a Content-Security-Policy header restricting script/style/connect sources.", fr: "Ajoutez un en-tête Content-Security-Policy qui restreint les sources de scripts, de styles et de connexions." } },
  "custom-404": { why: { en: "Fetches a missing route and checks the returned 404 page offers a way back — internal links, a nav, or a search box — rather than being a dead end. A helpful 404 keeps visitors on the site and gives crawlers links to follow.", fr: "Récupère une route inexistante et vérifie que la page 404 renvoyée offre une issue — liens internes, une navigation ou un champ de recherche — au lieu d'être une impasse. Une page 404 utile retient les visiteurs sur le site et donne aux robots des liens à suivre." }, fix: { en: "Return a branded 404 (with a 404 status) that links home and to key sections.", fr: "Renvoyez une page 404 personnalisée (avec un code 404) qui renvoie vers l'accueil et les sections clés." } },
  "cwv-assessment": { why: { en: "Reports the overall Core Web Vitals verdict (fast, average, or slow) that Google's real-user CrUX dataset assigns to your site. It's a headline signal of whether your pages clear Google's speed bar.", fr: "Rapporte le verdict global des Core Web Vitals (rapide, moyen ou lent) que le jeu de données CrUX de Google, basé sur de vrais utilisateurs, attribue à votre site. C’est un signal clé indiquant si vos pages franchissent la barre de vitesse de Google." }, fix: { en: "Fix whichever of LCP / CLS / INP is worst first; re-measure once field data updates.", fr: "Corrigez d’abord la métrique la plus mauvaise parmi LCP / CLS / INP ; re-mesurez une fois les données de terrain mises à jour." } },
  "cwv-cls": { why: { en: "Checks Cumulative Layout Shift, how much the page visually jumps around while loading, from real-user field data. Google uses it as a ranking signal and a stable layout signals a well-built, trustworthy page.", fr: "Vérifie le Cumulative Layout Shift, l’ampleur des sauts visuels de la page pendant son chargement, à partir des données de terrain réelles. Google l’utilise comme signal de classement, et une mise en page stable témoigne d’une page bien construite et fiable." }, fix: { en: "Set width/height on media and ads; reserve space for injected banners/embeds.", fr: "Définissez width/height sur les médias et les publicités ; réservez l’espace pour les bannières et intégrations injectées." } },
  "cwv-inp": { why: { en: "Checks Interaction to Next Paint — how quickly the page responds to clicks and taps — from real-user field data. Sluggish interactivity is a Core Web Vitals ranking factor and frustrates visitors.", fr: "Vérifie l’Interaction to Next Paint — la rapidité avec laquelle la page réagit aux clics et aux appuis — à partir des données de terrain réelles. Une interactivité lente est un facteur de classement des Core Web Vitals et frustre les visiteurs." }, fix: { en: "Break up long JS tasks; defer third-party scripts; minimise main-thread work.", fr: "Fractionnez les longues tâches JS ; différez les scripts tiers ; réduisez le travail du thread principal." } },
  "cwv-lcp": { why: { en: "Checks Largest Contentful Paint — how long until the page's main content renders — from real-user (CrUX) field data, falling back to lab data. Slow main content hurts search rankings and can make crawlers time out before they see it.", fr: "Vérifie le Largest Contentful Paint — le temps avant l’affichage du contenu principal de la page — à partir des données de terrain (CrUX) issues de vrais utilisateurs, avec repli sur les données de laboratoire. Un contenu principal lent nuit au classement et peut faire expirer les crawlers avant qu’ils ne le voient." }, fix: { en: "Preload the LCP image/font; remove render-blocking CSS/JS ahead of it; speed up the server.", fr: "Préchargez l’image/police du LCP ; supprimez le CSS/JS qui bloque le rendu et la précède ; accélérez le serveur." } },
  "cwv-ttfb": { why: { en: "Checks Time To First Byte — how fast your server starts responding — from real-user field data with a lab fallback. A slow server delays everything else and can make AI crawlers give up before fetching the page.", fr: "Vérifie le Time To First Byte — la rapidité avec laquelle votre serveur commence à répondre — à partir des données de terrain réelles, avec repli sur le laboratoire. Un serveur lent retarde tout le reste et peut pousser les crawlers IA à abandonner avant de récupérer la page." }, fix: { en: "Add edge caching / a CDN; enable keep-alive and HTTP/2; speed up server response.", fr: "Ajoutez un cache en périphérie / un CDN ; activez le keep-alive et HTTP/2 ; accélérez la réponse du serveur." } },
  "dom-size": { why: { en: "Counts the number of DOM elements and the maximum nesting depth of the homepage. A large or deeply nested DOM slows rendering and makes the page harder for browsers and crawlers to parse.", fr: "Compte le nombre d'éléments du DOM et la profondeur d'imbrication maximale de la page d'accueil. Un DOM volumineux ou trop imbriqué ralentit le rendu et rend la page plus difficile à analyser pour les navigateurs et les robots." }, fix: { en: "Simplify markup; virtualize long lists; flatten deep nesting.", fr: "Simplifiez le balisage ; virtualisez les longues listes ; aplatissez les imbrications profondes." } },
  "extractable-structure": { why: { en: "On substantial pages (≥150 words), checks for lists (<ul>/<ol>) or data tables with <th> headers in the main content. Structured content is far easier for AI engines to parse and reuse than an unbroken wall of prose.", fr: "Sur les pages substantielles (≥150 mots), recherche des listes (<ul>/<ol>) ou des tableaux de données avec en-têtes <th> dans le contenu principal. Un contenu structuré est bien plus facile à analyser et à réutiliser pour les moteurs d’IA qu’un long bloc de prose." }, fix: { en: "Break comparisons/steps/specs into <ul>/<ol> bullets or a data <table> with <th> headers.", fr: "Structurez comparaisons/étapes/spécifications en puces <ul>/<ol> ou en <table> de données avec des en-têtes <th>." } },
  "favicon": { why: { en: "Checks for a favicon and an apple-touch-icon on the homepage. These icons make the site recognizable in browser tabs, bookmarks, and on mobile home screens, reinforcing brand trust.", fr: "Vérifie la présence d’un favicon et d’une apple-touch-icon sur la page d’accueil. Ces icônes rendent le site reconnaissable dans les onglets du navigateur, les favoris et sur les écrans d’accueil mobiles, ce qui renforce la confiance dans la marque." }, fix: { en: "Add <link rel=\"icon\" href=\"...\"> (or serve /favicon.ico) and <link rel=\"apple-touch-icon\" href=\"...\">.", fr: "Ajoutez <link rel=\"icon\" href=\"...\"> (ou servez /favicon.ico) et <link rel=\"apple-touch-icon\" href=\"...\">." } },
  "figure-caption": { why: { en: "Checks that non-decorative content images are wrapped in a <figure> with a <figcaption>. Captions give images textual context that both search engines and AI models can read and use.", fr: "Vérifie que les images de contenu non décoratives sont encadrées dans une <figure> avec une <figcaption>. Les légendes donnent aux images un contexte textuel que les moteurs de recherche comme les modèles d’IA peuvent lire et exploiter." }, fix: { en: "Wrap explanatory images in <figure> with a <figcaption>.", fr: "Encadrez les images explicatives dans une <figure> avec une <figcaption>." } },
  "form-labels": { why: { en: "Checks that every input, select, and textarea (excluding hidden and button-type inputs) has an accessible name from a `<label>`, `aria-label`, or `aria-labelledby`. Without one, screen-reader users can't tell what a field is for and the form becomes unusable.", fr: "Vérifie que chaque champ input, select et textarea (hors champs cachés et boutons) possède un nom accessible fourni par un `<label>`, un `aria-label` ou un `aria-labelledby`. Sans cela, les utilisateurs de lecteurs d'écran ne savent pas à quoi sert un champ et le formulaire devient inutilisable." }, fix: { en: "Associate every input/select/textarea with a <label>, aria-label, or aria-labelledby.", fr: "Associez chaque input/select/textarea à un `<label>`, un `aria-label` ou un `aria-labelledby`." } },
  "headings-outline": { why: { en: "Verifies each sampled page has exactly one <h1> and never skips a heading level. A clean heading hierarchy is how crawlers and AI models parse page structure and pull out sections to cite.", fr: "Vérifie que chaque page échantillonnée comporte exactement un <h1> et ne saute jamais de niveau de titre. Une hiérarchie de titres propre permet aux robots et aux modèles d’IA d’analyser la structure de la page et d’en extraire les sections à citer." }, fix: { en: "Use exactly one <h1> per page and nest H2/H3/... without skipping a level.", fr: "Utilisez exactement un <h1> par page et imbriquez les H2/H3/… sans sauter de niveau." } },
  "homepage-ok": { why: { en: "Verifies the root URL responds with HTTP 200. If the homepage errors or is unreachable, crawlers have no entry point to index and assistants have nothing to cite.", fr: "Vérifie que l’URL racine répond en HTTP 200. Si la page d’accueil renvoie une erreur ou est injoignable, les robots n’ont aucun point d’entrée à indexer et les assistants n’ont rien à citer." }, fix: { en: "Ensure the root URL serves a 200 HTML page without requiring JavaScript.", fr: "Assurez-vous que l'URL racine renvoie une page HTML en 200, sans nécessiter JavaScript." } },
  "hreflang": { why: { en: "For each declared hreflang alternate, verifies that it loads (200) and links reciprocally back to the page that referenced it. Correct, reciprocal hreflang tells search and answer engines which language or region version to serve, preventing the wrong variant from surfacing.", fr: "Pour chaque alternative hreflang déclarée, vérifie qu’elle se charge (200) et renvoie réciproquement vers la page qui la référence. Un hreflang correct et réciproque indique aux moteurs de recherche et de réponse quelle version linguistique ou régionale servir, évitant qu’une mauvaise variante ne remonte." }, fix: { en: "Every hreflang alternate must return 200 and declare hreflang links back to its language variants.", fr: "Chaque alternative hreflang doit renvoyer un code 200 et déclarer en retour des liens hreflang vers ses variantes linguistiques." } },
  "hreflang-x-default": { why: { en: "On pages that use hreflang, validates the BCP-47 language codes and checks for an x-default alternate, a self-referencing entry, and absolute URLs. Correct hreflang tells search engines which language or region version to serve; gaps make the wrong version surface or the whole set be ignored.", fr: "Sur les pages qui utilisent hreflang, valide les codes de langue BCP-47 et vérifie la présence d'un alternate x-default, d'une entrée autoréférencée et d'URL absolues. Un hreflang correct indique aux moteurs de recherche quelle version linguistique ou régionale servir ; des lacunes font remonter la mauvaise version ou font ignorer l'ensemble." }, fix: { en: "Add an x-default alternate and a self-referencing hreflang; use absolute URLs.", fr: "Ajoutez un attribut alternate x-default et un hreflang autoréférencé ; utilisez des URL absolues." } },
  "hsts": { why: { en: "Checks for a Strict-Transport-Security header with a max-age of at least 180 days, which forces browsers to reach the site only over HTTPS. Enforced HTTPS protects visitors from downgrade attacks and reinforces the security posture that builds search and AI-engine trust.", fr: "Vérifie la présence d’un en-tête Strict-Transport-Security avec un max-age d’au moins 180 jours, qui force les navigateurs à ne joindre le site qu’en HTTPS. Le HTTPS imposé protège les visiteurs des attaques de rétrogradation et renforce la posture de sécurité qui bâtit la confiance des moteurs de recherche et d’IA." }, fix: { en: "Add `Strict-Transport-Security: max-age=31536000; includeSubDomains`.", fr: "Ajoutez `Strict-Transport-Security: max-age=31536000; includeSubDomains`." } },
  "html-lang": { why: { en: "Verifies that every sampled page declares a valid BCP-47 language code in `<html lang>`. Screen readers rely on it to pronounce content correctly, and search and AI answer engines use it to serve the page to the right-language audience.", fr: "Vérifie que chaque page échantillonnée déclare un code de langue BCP-47 valide dans `<html lang>`. Les lecteurs d'écran s'en servent pour prononcer correctement le contenu, et les moteurs de recherche et d'IA l'utilisent pour proposer la page au public de la bonne langue." }, fix: { en: "Add <html lang=\"…\"> with a valid BCP-47 code (e.g. \"en\", \"fr-CA\") to every page.", fr: "Ajoutez `<html lang=\"…\">` avec un code BCP-47 valide (par exemple « en », « fr-CA ») sur chaque page." } },
  "html-weight": { why: { en: "Measures the size of the HTML document, flagging anything over 100KB. Bloated HTML slows the first render and costs search and AI crawlers more to fetch and parse.", fr: "Mesure la taille du document HTML et signale tout ce qui dépasse 100 Ko. Un HTML surchargé ralentit le premier rendu et coûte plus cher à récupérer et analyser pour les robots de recherche et d'IA." }, fix: { en: "Externalize large inline blobs; paginate huge pages.", fr: "Externalisez les gros blocs inline ; paginez les pages trop volumineuses." } },
  "https": { why: { en: "Confirms the site is served over HTTPS after following redirects. Secure transport is a baseline ranking and trust signal, and many crawlers and AI agents skip or downrank pages that are not on HTTPS.", fr: "Confirme que le site est servi en HTTPS une fois les redirections suivies. Le transport sécurisé est un signal de base pour le classement et la confiance, et de nombreux robots et agents IA ignorent ou déclassent les pages qui ne sont pas en HTTPS." }, fix: { en: "Serve the site over HTTPS.", fr: "Servez le site en HTTPS." } },
  "iframe-title": { why: { en: "Checks that every `<iframe>` has a `title` or `aria-label`. Without one, screen readers announce only a generic \"frame\" and users can't tell what embedded content it contains.", fr: "Vérifie que chaque `<iframe>` possède un `title` ou un `aria-label`. Sans cela, les lecteurs d'écran n'annoncent qu'un « cadre » générique et l'utilisateur ne sait pas quel contenu intégré il renferme." }, fix: { en: "Add a descriptive title=\"…\" to every <iframe>.", fr: "Ajoutez un `title=\"…\"` descriptif à chaque `<iframe>`." } },
  "images-alt": { why: { en: "Measures the share of <img> elements that carry an alt attribute across the sampled pages. Alt text lets screen readers and AI models understand images, improving accessibility and the semantic richness engines can extract from the page.", fr: "Mesure la proportion d’éléments <img> possédant un attribut alt sur les pages échantillonnées. Le texte alternatif permet aux lecteurs d’écran et aux modèles d’IA de comprendre les images, améliorant l’accessibilité et la richesse sémantique que les moteurs peuvent extraire de la page." }, fix: { en: "Add descriptive alt text (alt=\"\" for purely decorative images) so LLMs and screen readers understand the images.", fr: "Ajoutez un texte alternatif descriptif (alt=\"\" pour les images purement décoratives) afin que les LLM et les lecteurs d’écran comprennent les images." } },
  "img-dimensions": { why: { en: "Checks what share of images across sampled pages declare an explicit width/height (or a CSS aspect-ratio). Missing dimensions make the layout jump as images load, worsening the CLS metric.", fr: "Vérifie, sur les pages échantillonnées, la proportion d'images qui déclarent une largeur/hauteur explicite (ou une propriété CSS aspect-ratio). Sans dimensions, la mise en page saute au chargement des images, ce qui dégrade la métrique CLS." }, fix: { en: "Set intrinsic width/height (or CSS aspect-ratio) on every <img> to avoid layout shift.", fr: "Définissez une largeur/hauteur intrinsèque (ou une propriété CSS aspect-ratio) sur chaque <img> pour éviter les décalages de mise en page." } },
  "img-lazy-loading": { why: { en: "Checks that the likely-LCP hero image loads eagerly while below-the-fold images are lazy-loaded. Lazy-loading the hero delays the largest paint, while eager-loading off-screen images wastes bandwidth.", fr: "Vérifie que l'image principale (probable LCP) se charge immédiatement tandis que les images sous la ligne de flottaison sont en chargement différé. Différer l'image principale retarde le plus grand affichage, et charger d'emblée les images hors écran gaspille de la bande passante." }, fix: { en: "Add loading=\"lazy\" to images below the fold; keep the first/LCP image eager.", fr: "Ajoutez loading=\"lazy\" aux images situées sous la ligne de flottaison ; gardez la première image (LCP) en chargement immédiat." } },
  "img-next-gen": { why: { en: "Measures what share of raster images are offered in next-gen formats like WebP or AVIF. These formats are far smaller than JPEG/PNG, so pages load faster and cost crawlers less to fetch.", fr: "Mesure la proportion d'images matricielles proposées dans des formats nouvelle génération comme WebP ou AVIF. Ces formats sont bien plus légers que le JPEG/PNG, donc les pages se chargent plus vite et coûtent moins cher à récupérer pour les robots." }, fix: { en: "Serve AVIF/WebP with <picture> + srcset (or a next-gen file extension) for raster images.", fr: "Servez vos images matricielles en AVIF/WebP via <picture> + srcset (ou une extension de fichier nouvelle génération)." } },
  "indexnow": { why: { en: "When an IndexNow key is supplied, verifies the ownership file /<key>.txt exists at the site root and contains exactly that key. IndexNow lets you instantly push new and updated URLs to search engines like Bing, so fresh content gets crawled and indexed faster.", fr: "Lorsqu’une clé IndexNow est fournie, vérifie que le fichier de propriété /<key>.txt existe à la racine du site et contient exactement cette clé. IndexNow permet de signaler instantanément aux moteurs comme Bing les URL nouvelles ou mises à jour, pour que le contenu récent soit exploré et indexé plus vite." }, fix: { en: "Publish a text file named <key>.txt at the site root containing exactly the key.", fr: "Publiez à la racine du site un fichier texte nommé <key>.txt contenant exactement la clé." } },
  "inline-head-volume": { why: { en: "Measures the volume of inline <style> and <script> in the <head>, flagging over 14KB. Excess inline code bloats every page load and cannot be cached separately.", fr: "Mesure le volume de <style> et <script> en inline dans le <head> et signale tout dépassement de 14 Ko. Trop de code inline alourdit chaque chargement de page et ne peut pas être mis en cache séparément." }, fix: { en: "Keep only minimal critical CSS inline in <head>; externalize the rest.", fr: "Ne conservez en inline dans le <head> que le CSS critique minimal ; externalisez le reste." } },
  "internal-linking": { why: { en: "Builds an internal link graph across sampled pages and flags pages with no outgoing internal links, orphans (nothing links to them), or pages more than 3 clicks from the homepage. Orphaned or deeply buried pages are rarely discovered, crawled, or ranked.", fr: "Construit un graphe de liens internes sur les pages échantillonnées et signale les pages sans lien interne sortant, les pages orphelines (aucun lien vers elles) ou situées à plus de 3 clics de la page d'accueil. Les pages orphelines ou trop profondes sont rarement découvertes, explorées ou classées." }, fix: { en: "Add contextual internal links via hub pages; keep key pages within 3 clicks of the homepage.", fr: "Ajoutez des liens internes contextuels via des pages pivots ; gardez les pages clés à moins de 3 clics de la page d'accueil." } },
  "json-ld": { why: { en: "Checks that the homepage contains at least one valid JSON-LD block. Structured data lets search engines and AI answer engines reliably identify your business, content, and key facts instead of guessing from raw text.", fr: "Vérifie que la page d’accueil contient au moins un bloc JSON-LD valide. Les données structurées permettent aux moteurs de recherche et aux moteurs de réponse IA d’identifier de façon fiable votre entreprise, votre contenu et vos informations clés, au lieu de les deviner à partir du texte brut." }, fix: { en: "Add a <script type=\"application/ld+json\"> block describing your business or content.", fr: "Ajoutez un bloc <script type=\"application/ld+json\"> décrivant votre entreprise ou votre contenu." } },
  "json-ld-entity": { why: { en: "Confirms the JSON-LD declares a meaningful entity (Organization, LocalBusiness, or Article) and, for businesses, includes name, address, and telephone. A clear entity is what AI assistants cite when they name and describe your site.", fr: "Confirme que le JSON-LD déclare une entité significative (Organization, LocalBusiness ou Article) et, pour les entreprises, inclut le nom, l’adresse et le téléphone. Une entité claire est ce que les assistants IA citent lorsqu’ils nomment et décrivent votre site." }, fix: { en: "Declare a relevant @type (LocalBusiness subtype, Organization, or Article).", fr: "Déclarez un @type pertinent (sous-type de LocalBusiness, Organization ou Article)." } },
  "json-ld-valid": { why: { en: "Validates that every JSON-LD block parses without errors and has a schema.org @context plus an explicit @type on each node. Malformed structured data is silently ignored by crawlers, so a single syntax slip can waste all your markup.", fr: "Valide que chaque bloc JSON-LD s’analyse sans erreur et possède un @context schema.org ainsi qu’un @type explicite sur chaque nœud. Des données structurées mal formées sont ignorées silencieusement par les robots : une seule erreur de syntaxe peut réduire tout votre balisage à néant." }, fix: { en: "Set \"@context\":\"https://schema.org\" and an explicit @type on every node.", fr: "Définissez \"@context\":\"https://schema.org\" et un @type explicite sur chaque nœud." } },
  "lab-fcp": { why: { en: "Checks First Contentful Paint (cross-checked with lab LCP) from PageSpeed Insights lab data — how quickly the first content appears — as the speed proxy when no real-user data is available. Fast first paint reassures visitors and crawlers that the page is loading.", fr: "Vérifie le First Contentful Paint (recoupé avec le LCP de laboratoire) à partir des données de laboratoire de PageSpeed Insights — la rapidité d’apparition du premier contenu — comme indicateur de vitesse en l’absence de données d’utilisateurs réels. Un premier affichage rapide rassure visiteurs et crawlers sur le fait que la page se charge." }, fix: { en: "Shorten the critical request chain; eliminate render-blocking CSS/JS; preload the hero resource.", fr: "Raccourcissez la chaîne de requêtes critiques ; éliminez le CSS/JS qui bloque le rendu ; préchargez la ressource principale (hero)." } },
  "lab-tbt": { why: { en: "Measures Total Blocking Time from lab data — how long the main thread stays blocked and unable to respond to input — as a stand-in for interactivity when no field data exists. High blocking time means a janky, unresponsive page.", fr: "Mesure le Total Blocking Time à partir des données de laboratoire — la durée pendant laquelle le thread principal reste bloqué et incapable de répondre aux interactions — comme substitut de l’interactivité en l’absence de données de terrain. Un temps de blocage élevé signale une page saccadée et peu réactive." }, fix: { en: "Reduce/defer JS; code-split; cut third-party tags to shorten long tasks.", fr: "Réduisez/différez le JS ; découpez le code (code-splitting) ; supprimez les balises tierces pour raccourcir les longues tâches." } },
  "landmarks": { why: { en: "Verifies each page uses semantic landmarks — a single `<main>` plus at least two of `<header>`/`<nav>`/`<footer>`. These regions let assistive tech and AI crawlers tell the main content apart from navigation and boilerplate.", fr: "Vérifie que chaque page utilise des repères sémantiques : un seul `<main>` plus au moins deux parmi `<header>`/`<nav>`/`<footer>`. Ces régions permettent aux technologies d'assistance et aux robots d'IA de distinguer le contenu principal de la navigation et des éléments répétitifs." }, fix: { en: "Wrap page content in a single <main> and use <header>/<nav>/<footer> landmark regions.", fr: "Placez le contenu de la page dans un unique `<main>` et utilisez les régions repères `<header>`/`<nav>`/`<footer>`." } },
  "lighthouse-perf": { why: { en: "Measures the Lighthouse lab performance score from PageSpeed Insights, a synthetic overall grade of page speed. A fast-loading page keeps human visitors engaged and helps AI crawlers fetch and index your content reliably.", fr: "Mesure le score de performance Lighthouse issu de PageSpeed Insights, une note globale synthétique de la vitesse de la page. Une page qui se charge vite retient les visiteurs et aide les crawlers IA à récupérer et indexer votre contenu de façon fiable." }, fix: { en: "Act on the top PSI opportunities: eliminate render-blocking resources, cut unused JS, optimise images.", fr: "Agissez sur les principales opportunités PSI : éliminez les ressources qui bloquent le rendu, réduisez le JS inutilisé, optimisez les images." } },
  "link-text": { why: { en: "Verifies that links have an accessible name from their text, an `aria-label`, or a child image's alt. Nameless icon or image links are unusable with a screen reader and give search and AI crawlers no clue about where they lead.", fr: "Vérifie que les liens disposent d'un nom accessible issu de leur texte, d'un `aria-label` ou de l'alt d'une image enfant. Les liens icônes ou images sans nom sont inutilisables au lecteur d'écran et ne donnent aux robots de recherche et d'IA aucune indication sur leur destination." }, fix: { en: "Give icon/image links an accessible name via link text, aria-label, or a child <img alt>.", fr: "Donnez aux liens icônes ou images un nom accessible via le texte du lien, un `aria-label` ou un `<img alt>` enfant." } },
  "llms-full-txt": { why: { en: "Checks that /llms-full.txt exists as plain text with substantial content (about 2000+ words under at least 2 headings). It gives AI crawlers the full text of your key pages in one clean file so they can quote and cite you accurately.", fr: "Vérifie que /llms-full.txt existe en texte brut avec un contenu substantiel (environ 2000 mots ou plus sous au moins 2 titres). Il fournit aux crawlers IA le texte intégral de vos pages clés dans un fichier propre, pour qu’ils puissent vous citer avec exactitude." }, fix: { en: "Add a /llms-full.txt containing the full text content of your key pages, under headings.", fr: "Ajoutez un /llms-full.txt contenant le texte intégral de vos pages clés, organisé sous des titres." } },
  "llms-txt": { why: { en: "Checks that /llms.txt exists, is served as plain text, and is well-structured (an H1 title, a one-line summary, a \"## section\", and at least 5 descriptive same-origin links). This file is a curated map that helps AI answer engines discover and understand your most important pages.", fr: "Vérifie que /llms.txt existe, est servi en texte brut et bien structuré (un titre H1, un résumé d’une ligne, une section « ## » et au moins 5 liens descriptifs de même origine). Ce fichier est une carte soigneusement sélectionnée qui aide les moteurs de réponse IA à découvrir et comprendre vos pages les plus importantes." }, fix: { en: "Add a /llms.txt file: an H1 title, a one-line summary, then \"## Section\" blocks of descriptive links.", fr: "Ajoutez un fichier /llms.txt : un titre H1, un résumé d’une ligne, puis des blocs « ## Section » de liens descriptifs." } },
  "meta-per-page": { why: { en: "Verifies each sampled page has a <title> of 10-70 characters and a meta description of 50-160 characters. These are what search engines and AI answer engines display and use to understand a page, so well-sized, unique ones improve click-through and how accurately your page is summarized.", fr: "Vérifie que chaque page échantillonnée possède un <title> de 10 à 70 caractères et une meta description de 50 à 160 caractères. Ce sont les éléments que les moteurs de recherche et les moteurs de réponse IA affichent et utilisent pour comprendre une page : bien dimensionnés et uniques, ils améliorent le taux de clic et la justesse du résumé de votre page." }, fix: { en: "Give every sampled page a unique 10-70 char <title> and a 50-160 char meta description.", fr: "Donnez à chaque page échantillonnée un <title> unique de 10 à 70 caractères et une meta description de 50 à 160 caractères." } },
  "meta-refresh": { why: { en: "Scans pages for <meta http-equiv=\"refresh\"> client-side redirects. These are slow and poorly understood by crawlers, which may not pass ranking signals or follow them at all — a server-side 301 is the reliable equivalent.", fr: "Recherche dans les pages les redirections côté client <meta http-equiv=\"refresh\">. Elles sont lentes et mal comprises par les robots, qui peuvent ne pas transmettre les signaux de classement ou ne pas les suivre du tout — une 301 côté serveur en est l'équivalent fiable." }, fix: { en: "Replace <meta http-equiv=\"refresh\"> redirects with a server 301.", fr: "Remplacez les redirections <meta http-equiv=\"refresh\"> par une redirection 301 côté serveur." } },
  "meta-robots-noindex": { why: { en: "Checks that sampled pages are not blocked from indexing by noindex/none in the meta robots tag or the X-Robots-Tag header (and flags header/meta conflicts and nofollow). A noindexed page is invisible to both search engines and AI crawlers, so it can never be found or cited.", fr: "Vérifie que les pages échantillonnées ne sont pas bloquées à l’indexation par noindex/none dans la balise meta robots ou l’en-tête X-Robots-Tag (et signale les conflits en-tête/meta ainsi que nofollow). Une page en noindex est invisible pour les moteurs de recherche comme pour les crawlers IA : elle ne peut donc jamais être trouvée ni citée." }, fix: { en: "Remove noindex/none from meta robots or the X-Robots-Tag header on pages that should be discoverable.", fr: "Retirez noindex/none de la balise meta robots ou de l’en-tête X-Robots-Tag sur les pages qui doivent être découvrables." } },
  "mixed-content": { why: { en: "Checks that an HTTPS page does not load subresources (scripts, stylesheets, iframes, images or media) over insecure http://. Mixed content triggers browser security warnings and can silently block resources, weakening the trust signals search and AI answer engines rely on.", fr: "Vérifie qu’une page HTTPS ne charge pas de sous-ressources (scripts, feuilles de style, iframes, images ou médias) via http:// non sécurisé. Le contenu mixte déclenche des avertissements de sécurité du navigateur et peut bloquer discrètement des ressources, ce qui affaiblit les signaux de confiance sur lesquels s’appuient les moteurs de recherche et d’IA." }, fix: { en: "Serve every script/stylesheet/iframe over https:// (or protocol-relative URLs).", fr: "Servez chaque script, feuille de style et iframe en https:// (ou via des URL relatives au protocole)." } },
  "nap-consistency": { why: { en: "Compares the business phone and address (NAP) shown in page footers across the sample and against your Organization/LocalBusiness JSON-LD, flagging divergences and conflicts. Consistent NAP builds local-SEO trust and lets search and AI engines cite your contact details with confidence.", fr: "Compare le téléphone et l'adresse de l'entreprise (NAP) affichés dans les pieds de page de l'échantillon et avec vos données JSON-LD Organization/LocalBusiness, en signalant divergences et conflits. Un NAP cohérent renforce la confiance pour le SEO local et permet aux moteurs de recherche et IA de citer vos coordonnées en toute confiance." }, fix: { en: "Render one canonical NAP from a single source; match JSON-LD.", fr: "Affichez un NAP canonique unique depuis une seule source ; faites-le correspondre au JSON-LD." } },
  "open-graph": { why: { en: "Checks that the homepage exposes complete Open Graph tags, including an absolute https image. These control how the site’s links look when shared or cited on social platforms and by AI assistants, boosting click-through and recognition.", fr: "Vérifie que la page d’accueil expose des balises Open Graph complètes, avec notamment une image en https absolu. Elles déterminent l’apparence des liens du site lorsqu’ils sont partagés ou cités sur les réseaux sociaux et par les assistants IA, améliorant le taux de clic et la reconnaissance." }, fix: { en: "Add the full Open Graph set: og:title, og:description, og:image (absolute https, >=1200x630), og:type, og:url.", fr: "Ajoutez l’ensemble complet des balises Open Graph : og:title, og:description, og:image (URL https absolue, ≥ 1200×630), og:type, og:url." } },
  "outbound-citations": { why: { en: "On substantial pages, checks for at least one external, non-social outbound link in the main content. Citing authoritative primary sources builds the credibility that AI answer engines reward when choosing what to cite.", fr: "Sur les pages substantielles, vérifie la présence d’au moins un lien sortant externe et non social dans le contenu principal. Citer des sources primaires faisant autorité renforce la crédibilité que les moteurs de réponse IA valorisent au moment de choisir leurs citations." }, fix: { en: "Cite primary/authoritative sources with real outbound links in your main content.", fr: "Citez des sources primaires ou faisant autorité avec de vrais liens sortants dans votre contenu principal." } },
  "pagination-canonical": { why: { en: "Detects paginated pages (?page=N, /page/N, or rel=next/prev) and checks that pages after page 1 canonicalize to themselves rather than to page 1. Pointing every page's canonical at page 1 tells search engines to drop the later pages, so content only listed there never gets indexed.", fr: "Détecte les pages paginées (?page=N, /page/N ou rel=next/prev) et vérifie que les pages au-delà de la page 1 se canonisent vers elles-mêmes plutôt que vers la page 1. Pointer la canonique de chaque page vers la page 1 indique aux moteurs de recherche d'ignorer les pages suivantes, si bien que le contenu qui n'y figure que là n'est jamais indexé." }, fix: { en: "Self-reference each paginated page; keep every page indexable.", fr: "Faites en sorte que chaque page paginée se référence elle-même ; gardez toutes les pages indexables." } },
  "permissions-policy": { why: { en: "Checks for a Permissions-Policy (or legacy Feature-Policy) header that disables powerful browser features such as camera, microphone and geolocation by default. Locking down unused features shrinks the attack surface and is a modern security signal of a well-maintained, trustworthy site.", fr: "Vérifie la présence d’un en-tête Permissions-Policy (ou de l’ancien Feature-Policy) qui désactive par défaut des fonctionnalités puissantes du navigateur comme la caméra, le microphone et la géolocalisation. Verrouiller les fonctionnalités inutilisées réduit la surface d’attaque et constitue un signal de sécurité moderne d’un site bien entretenu et digne de confiance." }, fix: { en: "Add `Permissions-Policy: geolocation=(), camera=(), microphone=()`.", fr: "Ajoutez `Permissions-Policy: geolocation=(), camera=(), microphone=()`." } },
  "redirect-chains": { why: { en: "Follows the redirect chain of the homepage and sampled URLs, flagging multi-hop chains, loops, or temporary redirects used for permanent moves. Extra hops slow crawlers, waste crawl budget, and can leave a page unindexed.", fr: "Suit la chaîne de redirections de la page d'accueil et des URL échantillonnées, en signalant les chaînes à plusieurs sauts, les boucles ou les redirections temporaires utilisées pour des déplacements permanents. Les sauts supplémentaires ralentissent les robots, gaspillent le budget de crawl et peuvent laisser une page non indexée." }, fix: { en: "Collapse multi-hop redirects into a single 301 to the final URL.", fr: "Réduisez les redirections à plusieurs sauts en une seule 301 vers l'URL finale." } },
  "redirect-hygiene": { why: { en: "Checks that the http:// version of the site permanently redirects (301) to https:// by inspecting the very first hop of the redirect chain. A permanent redirect consolidates ranking signals on one secure canonical origin and keeps crawlers off an insecure or duplicate version.", fr: "Vérifie que la version http:// du site redirige de façon permanente (301) vers https:// en inspectant le tout premier saut de la chaîne de redirection. Une redirection permanente regroupe les signaux de référencement sur une seule origine canonique sécurisée et évite aux crawlers de rester sur une version non sécurisée ou dupliquée." }, fix: { en: "Add a 301 redirect from HTTP to HTTPS.", fr: "Ajoutez une redirection 301 de HTTP vers HTTPS." } },
  "referrer-policy": { why: { en: "Checks for a valid, non-leaky Referrer-Policy header that controls how much of your URL is shared when visitors follow links to other sites. A privacy-preserving policy avoids leaking sensitive URLs and reflects the security hygiene that reinforces overall site trust.", fr: "Vérifie la présence d’un en-tête Referrer-Policy valide et non fuyant, qui contrôle la part de votre URL partagée lorsque les visiteurs suivent des liens vers d’autres sites. Une politique respectueuse de la vie privée évite de divulguer des URL sensibles et reflète l’hygiène de sécurité qui renforce la confiance globale envers le site." }, fix: { en: "Add `Referrer-Policy: strict-origin-when-cross-origin`.", fr: "Ajoutez `Referrer-Policy: strict-origin-when-cross-origin`." } },
  "render-blocking-css": { why: { en: "Counts render-blocking stylesheets in the <head>. Each one blocks the first paint until it downloads, delaying how quickly visitors and crawlers see content.", fr: "Compte les feuilles de style bloquantes dans le <head>. Chacune bloque le premier affichage tant qu'elle n'est pas téléchargée, retardant le moment où les visiteurs et les robots voient le contenu." }, fix: { en: "Inline critical CSS; defer the rest (media queries / preload+onload); reduce requests.", fr: "Intégrez le CSS critique en inline ; différez le reste (media queries / preload+onload) ; réduisez le nombre de requêtes." } },
  "render-blocking-js": { why: { en: "Counts scripts in the <head> that block rendering on each sampled page. Render-blocking scripts delay when the page becomes visible, hurting perceived speed and Core Web Vitals.", fr: "Compte, sur chaque page échantillonnée, les scripts du <head> qui bloquent le rendu. Ces scripts bloquants retardent l'affichage de la page, ce qui dégrade la vitesse perçue et les Core Web Vitals." }, fix: { en: "Add defer/async (or type=module) to head <script src>, or move scripts to the end of <body>.", fr: "Ajoutez defer/async (ou type=module) aux <script src> du <head>, ou déplacez les scripts en fin de <body>." } },
  "resource-hints": { why: { en: "Checks whether cross-origin scripts and stylesheets have a preconnect or dns-prefetch hint. These hints let the browser set up third-party connections early, shaving time off the load.", fr: "Vérifie si les scripts et feuilles de style provenant d'autres domaines disposent d'un indice preconnect ou dns-prefetch. Ces indices permettent au navigateur d'établir tôt les connexions tierces, ce qui réduit le temps de chargement." }, fix: { en: "Add <link rel=\"preconnect\" href=\"...\"> for critical third-party origins and rel=preload for the LCP image/key font.", fr: "Ajoutez <link rel=\"preconnect\" href=\"...\"> pour les origines tierces critiques et rel=preload pour l'image LCP et les polices essentielles." } },
  "robots-directives": { why: { en: "Checks the homepage for blocking robots directives (noindex/noai) in the X-Robots-Tag header or the meta robots tag. Such a directive on the homepage tells search and AI crawlers to skip the page entirely, making it invisible in results and AI answers.", fr: "Recherche sur la page d'accueil des directives robots bloquantes (noindex/noai) dans l'en-tête X-Robots-Tag ou la balise meta robots. Une telle directive sur la page d'accueil demande aux robots de recherche et d'IA d'ignorer entièrement la page, la rendant invisible dans les résultats et les réponses des IA." }, fix: { en: "Remove noindex/noai from the X-Robots-Tag header and <meta name=\"robots\"> unless intentional.", fr: "Retirez noindex/noai de l'en-tête X-Robots-Tag et de la balise <meta name=\"robots\">, sauf si c'est intentionnel." } },
  "robots-exists": { why: { en: "Verifies that /robots.txt exists and is served as text/plain rather than an HTML fallback page. It is the first file search and AI crawlers request to learn what they may access, so a missing or misserved one leaves them without an explicit crawl policy or a pointer to your sitemap.", fr: "Vérifie que /robots.txt existe et est servi en text/plain plutôt qu'en page HTML de repli. C'est le premier fichier que demandent les robots de recherche et d'IA pour savoir ce qu'ils peuvent explorer : s'il manque ou est mal servi, ils n'ont aucune politique d'exploration explicite ni de renvoi vers votre sitemap." }, fix: { en: "Create a robots.txt file at the site root.", fr: "Créez un fichier robots.txt à la racine du site." } },
  "robots-wellformed": { why: { en: "Checks that robots.txt is syntactically well-formed — plain text, only recognized directives (User-agent, Allow, Disallow, Sitemap…), and no Allow/Disallow before the first User-agent line. A malformed file is interpreted unpredictably by different crawlers, silently changing what they fetch.", fr: "Contrôle que le robots.txt est syntaxiquement correct — texte brut, uniquement des directives reconnues (User-agent, Allow, Disallow, Sitemap…), et aucun Allow/Disallow avant la première ligne User-agent. Un fichier mal formé est interprété de façon imprévisible selon les robots, modifiant en silence ce qu'ils explorent." }, fix: { en: "Serve a valid text/plain robots.txt with a User-agent group and a Sitemap: line; never return HTML for it.", fr: "Servez un robots.txt valide en text/plain, avec un groupe User-agent et une ligne Sitemap: ; ne renvoyez jamais de HTML à sa place." } },
  "schema-coverage": { why: { en: "Checks how many sampled pages include valid JSON-LD structured data. Structured data helps search engines and AI assistants understand what a page is about and makes it eligible for rich results and citations.", fr: "Vérifie combien de pages échantillonnées contiennent des données structurées JSON-LD valides. Les données structurées aident les moteurs de recherche et les assistants IA à comprendre le sujet d’une page et la rendent éligible aux résultats enrichis et aux citations." }, fix: { en: "Add page-appropriate JSON-LD (Article for posts, Product for product pages, BreadcrumbList for sections).", fr: "Ajoutez un JSON-LD adapté à chaque page (Article pour les articles, Product pour les pages produit, BreadcrumbList pour les rubriques)." } },
  "sd-article": { why: { en: "Checks that pages carrying Article, NewsArticle or BlogPosting markup have complete fields — headline, a structured author, publish and modified dates, an adequately sized image and a publisher logo. Rich, complete article data helps search and AI answer engines understand, date and confidently cite your content.", fr: "Vérifie que les pages balisées Article, NewsArticle ou BlogPosting comportent des champs complets : titre (headline), auteur structuré, dates de publication et de modification, image de taille suffisante et logo de l'éditeur. Des données d'article complètes aident les moteurs de recherche et les moteurs de réponse IA à comprendre, dater et citer votre contenu en toute confiance." }, fix: { en: "Add headline/author/datePublished + dateModified/image/publisher.logo.", fr: "Ajoutez headline/author/datePublished + dateModified/image/publisher.logo." } },
  "sd-breadcrumb": { why: { en: "On interior (non-homepage) pages, checks for a valid BreadcrumbList with contiguously ordered positions and names, or a visible breadcrumb navigation element. Breadcrumbs express your site's hierarchy, improving rich results and helping search and AI engines understand where each page sits.", fr: "Sur les pages internes (hors page d'accueil), recherche un BreadcrumbList valide avec des positions et des noms ordonnés de façon continue, ou un élément de navigation en fil d'Ariane visible. Le fil d'Ariane exprime la hiérarchie de votre site, améliore les résultats enrichis et aide les moteurs de recherche et IA à situer chaque page." }, fix: { en: "Emit BreadcrumbList with ordered position/name/item.", fr: "Émettez un BreadcrumbList avec position/name/item ordonnés." } },
  "sd-consistency": { why: { en: "Compares key JSON-LD values (name, headline, price, rating) against the visible page text to catch markup that describes hidden or absent content. Structured data that contradicts the page can be treated as spam and get your rich results demoted or removed.", fr: "Compare les valeurs clés du JSON-LD (name, headline, prix, note) au texte visible de la page pour repérer un balisage décrivant du contenu masqué ou absent. Des données structurées en contradiction avec la page peuvent être considérées comme du spam et entraîner la rétrogradation ou la suppression de vos résultats enrichis." }, fix: { en: "Only mark up content visible on the page.", fr: "Ne balisez que le contenu visible sur la page." } },
  "sd-entity-grounding": { why: { en: "Examines the sameAs links and rewards having at least two official profiles, ideally one pointing to Wikipedia or Wikidata. Linking to these knowledge-graph anchors helps AI engines disambiguate your entity from others with the same name.", fr: "Examine les liens sameAs et valorise la présence d’au moins deux profils officiels, idéalement un pointant vers Wikipédia ou Wikidata. Ces ancres vers le graphe de connaissances aident les moteurs IA à distinguer votre entité d’autres portant le même nom." }, fix: { en: "List ≥2 official profile URLs in sameAs, including Wikipedia/Wikidata if available.", fr: "Indiquez au moins 2 URL de profils officiels dans sameAs, y compris Wikipédia/Wikidata si disponible." } },
  "sd-faq": { why: { en: "Detects FAQ-style content on the page (schema question/answer pairs, expandable details blocks, or question-shaped headings) and flags it when it isn't backed by FAQPage or QAPage structured data. Marking FAQs as schema makes each question and answer machine-readable, so search and AI assistants can surface direct answers.", fr: "Détecte le contenu de type FAQ sur la page (paires question/réponse en schéma, blocs dépliables ou titres formulés comme des questions) et le signale lorsqu'il n'est pas adossé à des données structurées FAQPage ou QAPage. Baliser les FAQ en schéma rend chaque question-réponse lisible par les machines, afin que les moteurs de recherche et les assistants IA puissent afficher des réponses directes." }, fix: { en: "Mark FAQs as FAQPage → Question → acceptedAnswer.text.", fr: "Balisez les FAQ en FAQPage → Question → acceptedAnswer.text." } },
  "sd-graph-integrity": { why: { en: "Checks that every @id reference in the JSON-LD graph points to a node that exists and that no @id is declared twice. Broken or duplicated references confuse parsers and can make them drop entities from your structured-data graph.", fr: "Vérifie que chaque référence @id du graphe JSON-LD pointe vers un nœud existant et qu’aucun @id n’est déclaré deux fois. Des références rompues ou dupliquées perturbent les analyseurs et peuvent leur faire écarter des entités de votre graphe de données structurées." }, fix: { en: "Use one @graph with a stable @id per entity; reference by @id.", fr: "Utilisez un seul @graph avec un @id stable par entité ; référencez par @id." } },
  "sd-localbusiness": { why: { en: "For a local business, verifies the NAP details (structured PostalAddress and telephone) plus geo coordinates and opening hours. Complete, structured local data is what powers map listings and lets AI assistants answer \"where\" and \"when\" questions about you.", fr: "Pour une entreprise locale, vérifie les informations NAP (PostalAddress structurée et téléphone) ainsi que les coordonnées géographiques et les horaires d’ouverture. Des données locales complètes et structurées alimentent les fiches cartographiques et permettent aux assistants IA de répondre aux questions « où » et « quand » à votre sujet." }, fix: { en: "Use structured PostalAddress + GeoCoordinates + openingHoursSpecification.", fr: "Utilisez une PostalAddress structurée + GeoCoordinates + openingHoursSpecification." } },
  "sd-organization": { why: { en: "Checks that an Organization or LocalBusiness node carries name, url, an absolute HTTPS logo, and sameAs profile links. These fields feed knowledge panels and let AI engines attach a verified identity and logo to your brand.", fr: "Vérifie qu’un nœud Organization ou LocalBusiness porte name, url, un logo HTTPS absolu et des liens de profils sameAs. Ces champs alimentent les panneaux de connaissances et permettent aux moteurs IA d’associer une identité et un logo vérifiés à votre marque." }, fix: { en: "Add name/url/square-logo/sameAs to the homepage @graph.", fr: "Ajoutez name/url/logo carré/sameAs au @graph de la page d’accueil." } },
  "sd-product": { why: { en: "Verifies that Product markup includes a valid offer (numeric price, three-letter ISO-4217 currency and an availability value), a brand, a GTIN or MPN identifier and an in-range rating. Complete product data powers rich results and lets AI engines answer price, stock and review questions accurately.", fr: "Vérifie que le balisage Product inclut une offre valide (prix numérique, devise ISO-4217 à trois lettres et disponibilité), une marque, un identifiant GTIN ou MPN et une note dans la plage autorisée. Des données produit complètes alimentent les résultats enrichis et permettent aux moteurs IA de répondre avec précision aux questions de prix, de stock et d'avis." }, fix: { en: "Add offers(price/priceCurrency/availability) + brand + gtin/mpn.", fr: "Ajoutez offers(price/priceCurrency/availability) + brand + gtin/mpn." } },
  "sd-special-types": { why: { en: "If the page marks up a HowTo, Event, or Recipe, validates the required fields for that type (steps, ISO dates and a location, or ingredients and instructions). Complete markup unlocks the rich results and step-by-step answers AI engines generate for these formats.", fr: "Si la page balise un HowTo, un Event ou une Recipe, valide les champs requis pour ce type (étapes, dates ISO et un lieu, ou ingrédients et instructions). Un balisage complet débloque les résultats enrichis et les réponses étape par étape que les moteurs IA génèrent pour ces formats." }, fix: { en: "Fill the required fields for the declared type; ISO dates, structured Place.", fr: "Renseignez les champs requis pour le type déclaré ; dates au format ISO, Place structuré." } },
  "sd-video": { why: { en: "When the page embeds a video, checks for VideoObject markup with name, description, an absolute thumbnail, and an ISO upload date. Without it, search and AI engines can't index the video, so it stays invisible in video results and rich answers.", fr: "Lorsque la page intègre une vidéo, vérifie la présence d’un balisage VideoObject avec name, description, une miniature absolue et une date de mise en ligne au format ISO. Sans cela, les moteurs de recherche et IA ne peuvent pas indexer la vidéo, qui reste invisible dans les résultats vidéo et les réponses enrichies." }, fix: { en: "Add VideoObject name/description/absolute thumbnailUrl/ISO uploadDate.", fr: "Ajoutez au VideoObject name/description/thumbnailUrl absolu/uploadDate au format ISO." } },
  "sd-website-searchaction": { why: { en: "For a WebSite entity, checks for a valid SearchAction whose urlTemplate contains {search_term_string} with a matching query-input. This can enable a sitelinks search box in results, letting users search your site directly from the SERP.", fr: "Pour une entité WebSite, vérifie la présence d’un SearchAction valide dont l’urlTemplate contient {search_term_string} avec un query-input correspondant. Cela peut activer une boîte de recherche de liens annexes dans les résultats, permettant aux utilisateurs de chercher sur votre site directement depuis la page de résultats." }, fix: { en: "Add potentialAction SearchAction with a urlTemplate and query-input.", fr: "Ajoutez un potentialAction SearchAction avec un urlTemplate et un query-input." } },
  "search-crawlers-allowed": { why: { en: "Verifies that robots.txt does not block the traditional search crawlers (Googlebot, Bingbot, and the * default) from the root. A site-wide disallow on these agents removes the site from classic search, which most AI answer engines still lean on.", fr: "Vérifie que le robots.txt ne bloque pas les robots de recherche classiques (Googlebot, Bingbot et le défaut *) à la racine. Un blocage à l'échelle du site pour ces agents fait disparaître le site de la recherche classique, sur laquelle s'appuient encore la plupart des moteurs de réponse IA." }, fix: { en: "Remove the site-wide \"Disallow: /\" rule for these user-agents; scope disallows to cart/search/admin paths.", fr: "Supprimez la règle « Disallow: / » qui bloque tout le site pour ces user-agents ; limitez les Disallow aux chemins panier/recherche/admin." } },
  "sitemap": { why: { en: "Checks that the site publishes a valid XML sitemap (discovered via robots.txt Sitemap lines or common paths) with a urlset/sitemapindex root and at least one <loc>, and that it is referenced in robots.txt. A sitemap lets search crawlers and AI answer engines discover every important page instead of only the ones they reach by following links.", fr: "Vérifie que le site publie un sitemap XML valide (repéré via les lignes Sitemap de robots.txt ou aux emplacements habituels), doté d’une racine urlset/sitemapindex et d’au moins un <loc>, et qu’il est référencé dans robots.txt. Un sitemap permet aux robots des moteurs de recherche et aux moteurs de réponse IA de découvrir chaque page importante, et pas seulement celles atteintes en suivant les liens." }, fix: { en: "Generate a sitemap.xml and reference it in robots.txt.", fr: "Générez un sitemap.xml et référencez-le dans robots.txt." } },
  "sitemap-index-limits": { why: { en: "For a sitemap index, checks that each referenced child sitemap is same-origin, reachable with a 200, valid XML, and stays under the 50,000-URL limit. Broken or oversized child sitemaps prevent crawlers from reading your full set of URLs.", fr: "Pour un index de sitemaps, vérifie que chaque sitemap enfant référencé est de même origine, accessible (200), en XML valide et reste sous la limite de 50 000 URL. Des sitemaps enfants cassés ou surdimensionnés empêchent les robots de lire l’ensemble complet de vos URL." }, fix: { en: "Split to <=50,000-URL children under one index; every child must be fetchable, valid XML, same-origin.", fr: "Répartissez en sitemaps enfants de 50 000 URL maximum sous un même index ; chaque enfant doit être accessible, en XML valide et de même origine." } },
  "sitemap-lastmod": { why: { en: "Checks that sitemap entries carry real, valid ISO-8601, non-future and varied <lastmod> dates rather than none, garbage, or one shared build date. Accurate last-modified dates tell crawlers which pages actually changed so they recrawl updated content promptly.", fr: "Vérifie que les entrées du sitemap portent des dates <lastmod> réelles, valides (ISO-8601), non futures et variées, plutôt qu’absentes, erronées ou toutes identiques à la date de build. Des dates de dernière modification exactes indiquent aux robots quelles pages ont réellement changé, afin qu’ils réexplorent rapidement le contenu mis à jour." }, fix: { en: "Give each URL a real, distinct, non-future <lastmod> reflecting its last edit.", fr: "Donnez à chaque URL un <lastmod> réel, distinct et non futur reflétant sa dernière modification." } },
  "sitemap-orphans": { why: { en: "Cross-references the sitemap against the site's internal link graph, flagging sitemap URLs that nothing links to and internally-linked pages absent from the sitemap. Key pages should be both listed and internally linked so crawlers and AI engines discover and trust them.", fr: "Recoupe le sitemap avec le graphe de liens internes du site, en signalant les URL du sitemap vers lesquelles rien ne pointe et les pages liées en interne absentes du sitemap. Les pages importantes doivent à la fois figurer dans le sitemap et être liées en interne, pour que les robots et les moteurs IA les découvrent et leur accordent de l’importance." }, fix: { en: "Ensure key pages are both internally linked and listed in the sitemap.", fr: "Veillez à ce que les pages clés soient à la fois liées en interne et listées dans le sitemap." } },
  "sitemap-urls-valid": { why: { en: "Samples sitemap URLs and confirms each is same-origin, HTTPS, returns 200 without redirecting, is not noindexed, and is self-canonical. Listing only clean, final, indexable URLs stops crawlers from wasting budget on redirects, dead links, or pages that should not be indexed.", fr: "Échantillonne des URL du sitemap et confirme que chacune est de même origine, en HTTPS, renvoie un 200 sans redirection, n’est pas en noindex et est auto-canonique. N’y lister que des URL propres, finales et indexables évite aux robots de gaspiller leur budget sur des redirections, des liens morts ou des pages à ne pas indexer." }, fix: { en: "List only final, 200, same-origin, self-canonical, indexable URLs in the sitemap.", fr: "Ne listez dans le sitemap que des URL finales, en 200, de même origine, auto-canoniques et indexables." } },
  "snippet-preview-directives": { why: { en: "Checks whether pages allow full text, image and video previews (max-snippet, max-image-preview, max-video-preview) instead of restricting them with nosnippet or zero limits. Generous preview directives let search results and AI answers show rich excerpts of your content, improving click-through and citation.", fr: "Vérifie si les pages autorisent des aperçus complets de texte, d’image et de vidéo (max-snippet, max-image-preview, max-video-preview) au lieu de les restreindre avec nosnippet ou des limites à zéro. Des directives d’aperçu généreuses permettent aux résultats de recherche et aux réponses des IA d’afficher de riches extraits de votre contenu, ce qui améliore le taux de clic et les citations." }, fix: { en: "Set max-image-preview:large, max-snippet:-1, max-video-preview:-1; remove stray nosnippet/max-snippet:0.", fr: "Définissez max-image-preview:large, max-snippet:-1, max-video-preview:-1 ; supprimez les nosnippet/max-snippet:0 résiduels." } },
  "soft-404": { why: { en: "Requests a random non-existent path and checks the server returns a real 404/410 status instead of a 200 or a redirect to the homepage (a soft 404). Search engines rely on the HTTP status to drop missing pages; a soft 404 lets empty routes get indexed as real content.", fr: "Demande un chemin inexistant aléatoire et vérifie que le serveur renvoie un vrai code 404/410 plutôt qu'un 200 ou une redirection vers la page d'accueil (un soft 404). Les moteurs de recherche s'appuient sur le code HTTP pour retirer les pages manquantes ; un soft 404 laisse des routes vides s'indexer comme du vrai contenu." }, fix: { en: "Make missing routes return a real 404/410 status, not 200.", fr: "Faites en sorte que les routes inexistantes renvoient un vrai code 404/410, pas un 200." } },
  "text-compression": { why: { en: "Checks whether the HTML is served with Brotli, zstd, or gzip compression. Compressing text responses cuts transfer size dramatically, speeding delivery to visitors and AI crawlers alike.", fr: "Vérifie si le HTML est servi avec une compression Brotli, zstd ou gzip. Compresser les réponses texte réduit fortement la taille transférée, ce qui accélère la livraison aussi bien aux visiteurs qu'aux robots d'IA." }, fix: { en: "Enable Brotli/gzip compression for text responses at the server/CDN.", fr: "Activez la compression Brotli/gzip pour les réponses texte au niveau du serveur ou du CDN." } },
  "title-description": { why: { en: "Checks that the homepage has a `<title>` and a meta description of the right length. These are the headline and summary that search engines and AI answer engines show and rely on to understand what the page is about.", fr: "Vérifie que la page d’accueil possède un `<title>` et une meta description de longueur adéquate. Ce sont le titre et le résumé que les moteurs de recherche et les moteurs de réponse IA affichent et utilisent pour comprendre le sujet de la page." }, fix: { en: "Add a <title> (10-70 chars) and a meta description (50-160 chars).", fr: "Ajoutez un `<title>` (10 à 70 caractères) et une meta description (50 à 160 caractères)." } },
  "title-h1-alignment": { why: { en: "Checks that the homepage <title> and <h1> share meaningful words once the brand is excluded. When the title and main heading agree on the subject, search engines and AI models receive a consistent signal about the page topic.", fr: "Vérifie que le <title> et le <h1> de la page d’accueil partagent des mots significatifs une fois la marque exclue. Lorsque le titre et le titre principal s’accordent sur le sujet, les moteurs de recherche et les modèles d’IA reçoivent un signal cohérent sur le thème de la page." }, fix: { en: "Keep the <h1> on the same subject as the <title>.", fr: "Gardez le <h1> sur le même sujet que le <title>." } },
  "title-pattern": { why: { en: "Checks that the homepage <title> leads with the topic and places the brand after a separator. A topic-first title tells search engines and AI assistants what the page is about before the brand name, improving relevance in results.", fr: "Vérifie que le <title> de la page d’accueil commence par le sujet et place la marque après un séparateur. Un titre qui met le sujet en avant indique aux moteurs de recherche et aux assistants IA de quoi parle la page avant le nom de marque, ce qui améliore la pertinence dans les résultats." }, fix: { en: "Format the title as \"Primary topic — Brand\" (e.g. \"Sourdough bread in Springfield — Example Bakery\").", fr: "Formatez le titre en « Sujet principal — Marque » (par ex. « Pain au levain à Springfield — Boulangerie Exemple »)." } },
  "trailing-slash": { why: { en: "For each sampled path, fetches the opposite trailing-slash form and flags it when that variant also returns 200 (duplicate content at two URLs). Serving the same page at both /page and /page/ splits ranking signals between the two URLs.", fr: "Pour chaque chemin échantillonné, récupère la forme à la barre oblique finale inversée et la signale si cette variante renvoie aussi un 200 (contenu dupliqué à deux URL). Servir la même page à la fois sur /page et /page/ disperse les signaux de classement entre les deux URL." }, fix: { en: "Enforce one slash convention with a 301 from the other form.", fr: "Imposez une seule convention de barre oblique finale avec une redirection 301 depuis l'autre forme." } },
  "twitter-card": { why: { en: "Verifies the page declares a Twitter Card (or a complete Open Graph fallback with title, description, and an absolute HTTPS image). This controls how links to your page render as rich previews when shared, improving click-through and how AI and social tools summarize the page.", fr: "Vérifie que la page déclare une Twitter Card (ou un repli Open Graph complet avec titre, description et image HTTPS absolue). Cela contrôle l’affichage des aperçus enrichis lorsqu’un lien est partagé, améliorant le taux de clic et la façon dont les outils IA et sociaux résument la page." }, fix: { en: "Add <meta name=\"twitter:card\" content=\"summary_large_image\"> or a complete Open Graph set.", fr: "Ajoutez <meta name=\"twitter:card\" content=\"summary_large_image\"> ou un jeu Open Graph complet." } },
  "unique-titles": { why: { en: "Verifies that every sampled page has a distinct <title> and meta description. Duplicate titles or descriptions make pages indistinguishable in search results and AI citations, which weakens relevance.", fr: "Vérifie que chaque page échantillonnée possède un <title> et une meta description distincts. Des titres ou descriptions en double rendent les pages indiscernables dans les résultats de recherche et les citations des IA, ce qui nuit à la pertinence." }, fix: { en: "Give every page a unique <title> and meta description so results and AI citations are distinguishable.", fr: "Donnez à chaque page un <title> et une meta description uniques afin que les résultats et les citations par les IA soient distinguables." } },
  "url-structure": { why: { en: "Inspects sampled and linked URLs for readability issues: excessive length, uppercase letters, underscores, deep nesting, or session/tracking query parameters. Clean, predictable URLs are easier for users and crawlers to parse, share, and de-duplicate.", fr: "Examine les URL échantillonnées et liées pour repérer les problèmes de lisibilité : longueur excessive, majuscules, tirets bas, imbrication trop profonde ou paramètres de session/suivi. Des URL propres et prévisibles sont plus faciles à analyser, partager et dédupliquer pour les utilisateurs comme pour les robots." }, fix: { en: "Use short, lowercase, hyphenated paths; strip session/tracking params from canonical URLs.", fr: "Utilisez des chemins courts, en minuscules et séparés par des traits d'union ; retirez les paramètres de session ou de suivi des URL canoniques." } },
  "viewport": { why: { en: "Checks for a mobile viewport meta tag on the homepage. Without it, pages render at desktop width on phones, hurting mobile usability, which search engines factor into ranking.", fr: "Vérifie la présence d’une balise meta viewport pour mobile sur la page d’accueil. Sans elle, les pages s’affichent à la largeur bureau sur téléphone, ce qui nuit à l’ergonomie mobile, un critère pris en compte par les moteurs de recherche pour le classement." }, fix: { en: "Add <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">.", fr: "Ajoutez `<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">`." } },
  "viewport-zoom": { why: { en: "Checks that the viewport meta doesn't block pinch-zoom via `user-scalable=no` or a `maximum-scale` below 2 (WCAG 1.4.4). Disabling zoom locks out low-vision users who need to enlarge text to read the page.", fr: "Vérifie que la balise meta viewport ne bloque pas le zoom tactile via `user-scalable=no` ou un `maximum-scale` inférieur à 2 (WCAG 1.4.4). Désactiver le zoom exclut les personnes malvoyantes qui ont besoin d'agrandir le texte pour lire la page." }, fix: { en: "Remove user-scalable=no and any maximum-scale below 2 from the viewport meta.", fr: "Retirez `user-scalable=no` et tout `maximum-scale` inférieur à 2 de la balise meta viewport." } },
  "www-consolidation": { why: { en: "Checks that only one host variant (www or apex) serves the site with a 200 while the other returns a single permanent 301 to it, with no redirect chains or loops. If both hosts serve content, search engines and AI crawlers see duplicate sites and split their ranking signals.", fr: "Vérifie qu'une seule variante d'hôte (www ou apex) sert le site avec un 200 tandis que l'autre renvoie une unique redirection permanente 301 vers elle, sans chaîne ni boucle. Si les deux hôtes servent du contenu, les moteurs de recherche et les robots d'IA voient des sites dupliqués et dispersent leurs signaux de classement." }, fix: { en: "301 the non-canonical host to a single canonical host.", fr: "Redirigez en 301 l'hôte non canonique vers un unique hôte canonique." } },
  "x-content-type-options": { why: { en: "Confirms the site sends `X-Content-Type-Options: nosniff`, which stops browsers from guessing (MIME-sniffing) a file's type instead of trusting the declared one. Blocking MIME-sniffing prevents a class of injection attacks and is a baseline security signal that trustworthy sites are expected to send.", fr: "Confirme que le site envoie `X-Content-Type-Options: nosniff`, qui empêche les navigateurs de deviner (MIME-sniffing) le type d’un fichier au lieu de se fier au type déclaré. Bloquer le MIME-sniffing prévient toute une catégorie d’attaques par injection et constitue un signal de sécurité de base attendu des sites dignes de confiance." }, fix: { en: "Add `X-Content-Type-Options: nosniff`.", fr: "Ajoutez `X-Content-Type-Options: nosniff`." } },
};

/** The check's purpose sentence in `lang`, if catalogued. */
export function checkWhy(id: string, lang: Lang): string | undefined {
  return CHECK_I18N[id]?.why[lang];
}

/**
 * Localized fix for a check. English reports keep the check's OWN fix (the
 * source of truth); only non-English reports substitute the catalogue translation,
 * falling back to the English fix when a check is not catalogued.
 */
export function checkFix(id: string, lang: Lang, fallback?: string): string | undefined {
  if (lang === 'en') return fallback;
  return CHECK_I18N[id]?.fix?.[lang] ?? fallback;
}
